const today = new Date().toISOString().split('T')[0];

const orderItems = $('Get Orders').all();
const callItems = $('Get Call Log').all();
const retryItems = $('Get Retry Queue').all();

// Today's data
const todayOrders = orderItems.filter(i => (i.json.timestamp || '').startsWith(today));
const todayCalls = callItems.filter(i => (i.json.timestamp || '').startsWith(today));

const totalOrders = todayOrders.length;
const codOrders = todayOrders.filter(o => o.json.is_cod === 'true' || o.json.is_cod === true).length;
const prepaidOrders = totalOrders - codOrders;
const confirmedOrders = todayOrders.filter(o => o.json.status === 'confirmed').length;
const declinedOrders = todayOrders.filter(o => o.json.status === 'declined').length;
const pendingOrders = todayOrders.filter(o => o.json.status === 'new' || o.json.status === 'call_initiated').length;

const totalCalls = todayCalls.length;
const successCalls = todayCalls.filter(c => c.json.status === 'confirmed' || c.json.outcome === 'confirmed').length;
const failedCalls = todayCalls.filter(c => c.json.status === 'failed' || c.json.outcome === 'failed').length;

const pendingRetries = retryItems.filter(r => r.json.status === 'pending_retry').length;
const exhaustedRetries = retryItems.filter(r => r.json.status === 'exhausted').length;

const totalRevenue = todayOrders.filter(o => o.json.status === 'confirmed').reduce((s, o) => s + (parseFloat(o.json.total_amount) || 0), 0);
const confirmRate = codOrders > 0 ? Math.round((confirmedOrders / codOrders) * 100) : 0;

const report = {
  date: today,
  total_orders: totalOrders,
  cod_orders: codOrders,
  prepaid_orders: prepaidOrders,
  confirmed: confirmedOrders,
  declined: declinedOrders,
  pending: pendingOrders,
  total_calls: totalCalls,
  successful_calls: successCalls,
  failed_calls: failedCalls,
  pending_retries: pendingRetries,
  exhausted_retries: exhaustedRetries,
  confirmation_rate: confirmRate,
  confirmed_revenue: totalRevenue
};

const html = `<div style='font-family:Arial,sans-serif;max-width:640px;margin:0 auto;'>
<h1 style='color:#1e293b;font-size:24px;margin-bottom:4px;'>eCommerce AI Voice Agent — Daily Report</h1>
<p style='color:#64748b;margin-top:0;'>${new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</p>

<div style='display:flex;gap:12px;margin:20px 0;flex-wrap:wrap;'>
  <div style='flex:1;min-width:120px;background:#eff6ff;border-radius:8px;padding:16px;text-align:center;'><div style='font-size:28px;font-weight:bold;color:#2563eb;'>${totalOrders}</div><div style='color:#64748b;font-size:13px;'>Total Orders</div></div>
  <div style='flex:1;min-width:120px;background:#f0fdf4;border-radius:8px;padding:16px;text-align:center;'><div style='font-size:28px;font-weight:bold;color:#16a34a;'>${confirmedOrders}</div><div style='color:#64748b;font-size:13px;'>Confirmed</div></div>
  <div style='flex:1;min-width:120px;background:#fef2f2;border-radius:8px;padding:16px;text-align:center;'><div style='font-size:28px;font-weight:bold;color:#dc2626;'>${declinedOrders}</div><div style='color:#64748b;font-size:13px;'>Declined</div></div>
  <div style='flex:1;min-width:120px;background:#fefce8;border-radius:8px;padding:16px;text-align:center;'><div style='font-size:28px;font-weight:bold;color:#ca8a04;'>${confirmRate}%</div><div style='color:#64748b;font-size:13px;'>Confirmation Rate</div></div>
</div>

<h3 style='color:#1e293b;border-bottom:2px solid #e2e8f0;padding-bottom:8px;'>Orders Breakdown</h3>
<table style='width:100%;border-collapse:collapse;'>
  <tr><td style='padding:6px 0;color:#64748b;'>COD Orders</td><td style='text-align:right;font-weight:bold;'>${codOrders}</td></tr>
  <tr><td style='padding:6px 0;color:#64748b;'>Prepaid Orders</td><td style='text-align:right;font-weight:bold;'>${prepaidOrders}</td></tr>
  <tr><td style='padding:6px 0;color:#64748b;'>Pending / In Progress</td><td style='text-align:right;font-weight:bold;color:#ca8a04;'>${pendingOrders}</td></tr>
  <tr><td style='padding:6px 0;color:#64748b;'>Confirmed Revenue</td><td style='text-align:right;font-weight:bold;color:#16a34a;'>$${totalRevenue.toFixed(2)}</td></tr>
</table>

<h3 style='color:#1e293b;border-bottom:2px solid #e2e8f0;padding-bottom:8px;margin-top:24px;'>Call Performance</h3>
<table style='width:100%;border-collapse:collapse;'>
  <tr><td style='padding:6px 0;color:#64748b;'>Total Calls</td><td style='text-align:right;font-weight:bold;'>${totalCalls}</td></tr>
  <tr><td style='padding:6px 0;color:#64748b;'>Successful</td><td style='text-align:right;font-weight:bold;color:#16a34a;'>${successCalls}</td></tr>
  <tr><td style='padding:6px 0;color:#64748b;'>Failed</td><td style='text-align:right;font-weight:bold;color:#dc2626;'>${failedCalls}</td></tr>
  <tr><td style='padding:6px 0;color:#64748b;'>Pending Retries</td><td style='text-align:right;font-weight:bold;'>${pendingRetries}</td></tr>
  <tr><td style='padding:6px 0;color:#64748b;'>Exhausted (Fallback)</td><td style='text-align:right;font-weight:bold;'>${exhaustedRetries}</td></tr>
</table>

<div style='margin-top:24px;padding:16px;background:#f8fafc;border-radius:8px;border:1px solid #e2e8f0;text-align:center;color:#64748b;font-size:13px;'>Generated by eCommerce AI Voice Agent</div>
</div>`;

return [{ json: { ...report, html_report: html } }];
